external_knowledge:
- High-capacity stations are those with more than 50 bike slots; 
- Recently maintained bikes are those serviced within the last 180 days; 
- "Rainy days" refers to weather conditions with descriptions containing the keyword 'rain'.

sql:
SELECT MAX(total_transactions) AS highest_total_transactions
FROM (
    SELECT start_station_id, end_station_id, weather_sit, SUM(total_count) AS total_transactions
    FROM usage_data
    GROUP BY start_station_id, end_station_id, weather_sit
) AS station_weather_totals;
